parameters.jsCode:
const rows = $input.all();

const data = $('Extract Order Data').first().json;

const found = rows.some(r => r.json.order_id === data.order_id);

return [
  {
    json: {
      shouldSend: !found,
      order_id: data.order_id,
      email: data.email,
      name: data.name,
      survey_link: `https://form.typeform.com/to/abc123?order_id=${data.order_id}`
    }
  }
];

const body = $json.body ?? $json;

const score = Number(body.csat_score ?? 0);

return [
  {
    json: {
      order_id: body.order_id,
      email: body.email,
      feedback: body.feedback || "",
      csat_score: score,

      // CX intelligence flags
      isLowCSAT: score <= 2,
      isNeutralCSAT: score === 3,
      isHighCSAT: score >= 4,

      timestamp: new Date().toISOString()
    }
  }
];
